428	\section{Stein finiteness of global sections}
429	\label{sec:module_finite_globalSections_iter044}
430	
431	The geometric input for the wholespace Hom-finiteness carrier is Stein's theorem: on a proper integral scheme over a field, global sections are finite-dimensional.
432	
433	\begin{theorem}\mathlibok
434	[Module-finiteness of the top-section map of a universally closed morphism]
435	  \label{thm:finite_appTop_of_universallyClosed}
436	  \lean{AlgebraicGeometry.finite_appTop_of_universallyClosed}
437	
438	  Let \(K\) be a commutative ring and \(X\) an integral scheme equipped with a
439	  universally closed, locally-of-finite-type morphism \(f : X \to \Spec K\).
440	  Then the ring map on top sections \(f^\sharp_{\top}\) is module-finite.
441	
442	  \textit{Provided by Mathlib.}
443	\end{theorem}
